// هيكل معلومات التطبيق
VkApplicationInfo appInfo = {};
appInfo.sType = VK_STRUCTURE_TYPE_APPLICATION_INFO;
appInfo.pApplicationName = "تطبيقي الأول";  // اسم التطبيق
appInfo.applicationVersion = VK_MAKE_VERSION(1, 0, 0);  // إصدار التطبيق
appInfo.pEngineName = "No Engine";  // اسم محرك الألعاب
appInfo.engineVersion = VK_MAKE_VERSION(1, 0, 0);  // إصدار المحرك
appInfo.apiVersion = VK_API_VERSION_1_0;  // إصدار Vulkan API

// هيكل معلومات إنشاء Instance
VkInstanceCreateInfo createInfo = {};
createInfo.sType = VK_STRUCTURE_TYPE_INSTANCE_CREATE_INFO;
createInfo.pApplicationInfo = &appInfo;  // معلومات التطبيق

// إنشاء Instance
VkInstance instance;
VkResult result = vkCreateInstance(&createInfo, nullptr, &instance);

// التحقق من نجاح العملية
if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنشاء Instance!");
}

// تدمير Instance قبل إنهاء البرنامج
// يجب تدمير جميع الكائنات المرتبطة به أولاً

vkDestroyDevice(device, nullptr);  // تدمير الجهاز أولاً

// ثم تدمير Instance
vkDestroyInstance(instance, nullptr);

// تعيين القيمة NULL لتجنب الاستخدام الخاطئ
instance = VK_NULL_HANDLE;

// الخطوة 1: الحصول على عدد الأجهزة المتاحة
uint32_t deviceCount = 0;
vkEnumeratePhysicalDevices(instance, &deviceCount, nullptr);

// التحقق من وجود أجهزة تدعم Vulkan
if (deviceCount == 0) {
    throw std::runtime_error("لا توجد بطاقات رسوميات تدعم Vulkan!");
}

// الخطوة 2: الحصول على قائمة الأجهزة
std::vector<VkPhysicalDevice> devices(deviceCount);
vkEnumeratePhysicalDevices(instance, &deviceCount, devices.data());

// الخطوة 3: اختيار الجهاز المناسب
VkPhysicalDevice physicalDevice = VK_NULL_HANDLE;
for (const auto& device : devices) {
    // التحقق من ملاءمة الجهاز
    if (isDeviceSuitable(device)) {
        physicalDevice = device;
        break;
    }
}

if (physicalDevice == VK_NULL_HANDLE) {
    throw std::runtime_error("لم يتم العثور على جهاز مناسب!");
}

// الحصول على خصائص الجهاز
VkPhysicalDeviceProperties deviceProperties;
vkGetPhysicalDeviceProperties(physicalDevice, &deviceProperties);

// طباعة معلومات الجهاز
std::cout << "اسم البطاقة: " << deviceProperties.deviceName << std::endl;
std::cout << "إصدار API: " 
          << VK_VERSION_MAJOR(deviceProperties.apiVersion) << "."
          << VK_VERSION_MINOR(deviceProperties.apiVersion) << "."
          << VK_VERSION_PATCH(deviceProperties.apiVersion) << std::endl;

// التحقق من نوع الجهاز
switch (deviceProperties.deviceType) {
    case VK_PHYSICAL_DEVICE_TYPE_INTEGRATED_GPU:
        std::cout << "نوع الجهاز: بطاقة مدمجة" << std::endl;
        break;
    case VK_PHYSICAL_DEVICE_TYPE_DISCRETE_GPU:
        std::cout << "نوع الجهاز: بطاقة منفصلة" << std::endl;
        break;
    case VK_PHYSICAL_DEVICE_TYPE_VIRTUAL_GPU:
        std::cout << "نوع الجهاز: بطاقة افتراضية" << std::endl;
        break;
    case VK_PHYSICAL_DEVICE_TYPE_CPU:
        std::cout << "نوع الجهاز: معالج مركزي" << std::endl;
        break;
    default:
        std::cout << "نوع الجهاز: غير معروف" << std::endl;
}

// الحصول على ميزات الجهاز
VkPhysicalDeviceFeatures deviceFeatures;
vkGetPhysicalDeviceFeatures(physicalDevice, &deviceFeatures);

// التحقق من دعم ميزات معينة
if (deviceFeatures.geometryShader) {
    std::cout << "الجهاز يدعم Geometry Shaders" << std::endl;
} else {
    std::cout << "الجهاز لا يدعم Geometry Shaders" << std::endl;
}

if (deviceFeatures.tessellationShader) {
    std::cout << "الجهاز يدعم Tessellation Shaders" << std::endl;
}

if (deviceFeatures.samplerAnisotropy) {
    std::cout << "الجهاز يدعم التصفية المتباينة" << std::endl;
}

if (deviceFeatures.fillModeNonSolid) {
    std::cout << "الجهاز يدعم وضع Wireframe" << std::endl;
}

// الخطوة 1: الحصول على عدد عائلات الطوابير
uint32_t queueFamilyCount = 0;
vkGetPhysicalDeviceQueueFamilyProperties(physicalDevice, &queueFamilyCount, nullptr);

// الخطوة 2: الحصول على خصائص كل عائلة
std::vector<VkQueueFamilyProperties> queueFamilies(queueFamilyCount);
vkGetPhysicalDeviceQueueFamilyProperties(physicalDevice, &queueFamilyCount, queueFamilies.data());

// الخطوة 3: إيجاد عائلة تدعم الرسوميات
int graphicsQueueFamilyIndex = -1;
for (uint32_t i = 0; i < queueFamilyCount; i++) {
    // التحقق من دعم العمليات الرسومية
    if (queueFamilies[i].queueFlags & VK_QUEUE_GRAPHICS_BIT) {
        graphicsQueueFamilyIndex = i;
        std::cout << "عائلة الطابور " << i << " تدعم الرسوميات" << std::endl;
        std::cout << "عدد الطوابير المتاحة: " << queueFamilies[i].queueCount << std::endl;
        break;
    }
}

if (graphicsQueueFamilyIndex == -1) {
    throw std::runtime_error("لم يتم العثور على عائلة طابور رسومية!");
}

// إعداد أولويات الطابور (قيمة بين 0.0 و 1.0)
float queuePriority = 1.0f;

// هيكل معلومات إنشاء الطابور
VkDeviceQueueCreateInfo queueCreateInfo = {};
queueCreateInfo.sType = VK_STRUCTURE_TYPE_DEVICE_QUEUE_CREATE_INFO;
queueCreateInfo.queueFamilyIndex = graphicsQueueFamilyIndex;  // فهرس عائلة الطابور
queueCreateInfo.queueCount = 1;  // عدد الطوابير المطلوبة
queueCreateInfo.pQueuePriorities = &queuePriority;  // أولويات الطوابير

// هيكل ميزات الجهاز (تفعيل الميزات المطلوبة)
VkPhysicalDeviceFeatures deviceFeatures = {};
deviceFeatures.samplerAnisotropy = VK_TRUE;  // تفعيل التصفية المتباينة
deviceFeatures.fillModeNonSolid = VK_TRUE;  // تفعيل Wireframe

// هيكل إنشاء الجهاز
VkDeviceCreateInfo createInfo = {};
createInfo.sType = VK_STRUCTURE_TYPE_DEVICE_CREATE_INFO;
createInfo.pQueueCreateInfos = &queueCreateInfo;  // معلومات الطوابير
createInfo.queueCreateInfoCount = 1;  // عدد هياكل معلومات الطوابير
createInfo.pEnabledFeatures = &deviceFeatures;  // الميزات المطلوبة

// إضافة الامتدادات المطلوبة (مثل VK_KHR_swapchain)
std::vector<const char*> deviceExtensions = {
    VK_KHR_SWAPCHAIN_EXTENSION_NAME
};
createInfo.enabledExtensionCount = static_cast<uint32_t>(deviceExtensions.size());
createInfo.ppEnabledExtensionNames = deviceExtensions.data();

// إنشاء الجهاز المنطقي
VkDevice device;
VkResult result = vkCreateDevice(physicalDevice, &createInfo, nullptr, &device);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنشاء الجهاز المنطقي!");
}

// انتظار انتهاء جميع العمليات على الجهاز
vkDeviceWaitIdle(device);

// تدمير جميع الموارد المرتبطة بالجهاز أولاً
// ... تدمير Buffers, Images, Pipelines, etc.

// تدمير الجهاز المنطقي
vkDestroyDevice(device, nullptr);

device = VK_NULL_HANDLE;

// الحصول على طابور الرسوميات
VkQueue graphicsQueue;
vkGetDeviceQueue(
    device,                    // الجهاز المنطقي
    graphicsQueueFamilyIndex,  // فهرس عائلة الطابور
    0,                         // فهرس الطابور (الأول)
    &graphicsQueue             // مقبض الطابور
);

// الحصول على طابور العرض (إذا كان مختلفاً)
VkQueue presentQueue;
if (presentQueueFamilyIndex != graphicsQueueFamilyIndex) {
    vkGetDeviceQueue(device, presentQueueFamilyIndex, 0, &presentQueue);
} else {
    presentQueue = graphicsQueue;  // نفس الطابور
}

// إعداد هيكل الإرسال
VkSubmitInfo submitInfo = {};
submitInfo.sType = VK_STRUCTURE_TYPE_SUBMIT_INFO;

// تحديد إشارات الانتظار (Semaphores)
VkSemaphore waitSemaphores[] = { imageAvailableSemaphore };
VkPipelineStageFlags waitStages[] = { VK_PIPELINE_STAGE_COLOR_ATTACHMENT_OUTPUT_BIT };
submitInfo.waitSemaphoreCount = 1;
submitInfo.pWaitSemaphores = waitSemaphores;
submitInfo.pWaitDstStageMask = waitStages;

// تحديد مخازن الأوامر للتنفيذ
submitInfo.commandBufferCount = 1;
submitInfo.pCommandBuffers = &commandBuffer;

// تحديد إشارات الإشعار
VkSemaphore signalSemaphores[] = { renderFinishedSemaphore };
submitInfo.signalSemaphoreCount = 1;
submitInfo.pSignalSemaphores = signalSemaphores;

// إرسال الأوامر للطابور
VkResult result = vkQueueSubmit(
    graphicsQueue,     // الطابور
    1,                 // عدد عمليات الإرسال
    &submitInfo,       // معلومات الإرسال
    inFlightFence      // السياج للإشارة بالانتهاء
);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إرسال مخزن الأوامر!");
}

// انتظار انتهاء جميع العمليات في الطابور
VkResult result = vkQueueWaitIdle(graphicsQueue);

if (result != VK_SUCCESS) {
    std::cerr << "خطأ في انتظار الطابور!" << std::endl;
}

// الآن يمكن التعامل مع الموارد بأمان
// مثل تحديث Vertex Buffers أو تبديل SwapChain

// انتظار خمول الجهاز بالكامل
vkDeviceWaitIdle(device);

// الآن يمكن إعادة إنشاء SwapChain بأمان
// أو تحديث موارد مشتركة بين عدة طوابير

// مثال: عند تغيير حجم النافذة
void onWindowResize() {
    vkDeviceWaitIdle(device);  // انتظار انتهاء العمليات

    // تدمير SwapChain القديم
    cleanupSwapChain();

    // إنشاء SwapChain جديد بالأبعاد الجديدة
    recreateSwapChain();
}

// هيكل معلومات إنشاء المستودع
VkCommandPoolCreateInfo poolInfo = {};
poolInfo.sType = VK_STRUCTURE_TYPE_COMMAND_POOL_CREATE_INFO;

// تحديد عائلة الطابور
poolInfo.queueFamilyIndex = graphicsQueueFamilyIndex;

// إضافة أعلام اختيارية
poolInfo.flags = VK_COMMAND_POOL_CREATE_RESET_COMMAND_BUFFER_BIT;  // السماح بإعادة تعيين مخزن الأوامر
// أو:
// poolInfo.flags = VK_COMMAND_POOL_CREATE_TRANSIENT_BIT;  // للمخازن قصيرة العمر

// إنشاء المستودع
VkCommandPool commandPool;
VkResult result = vkCreateCommandPool(device, &poolInfo, nullptr, &commandPool);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنشاء مستودع الأوامر!");
}

// تدمير مستودع الأوامر
// ملاحظة: جميع مخازن الأوامر من هذا المستودع ستُدمّر تلقائياً

vkDestroyCommandPool(device, commandPool, nullptr);
commandPool = VK_NULL_HANDLE;

// هيكل معلومات تخصيص مخازن الأوامر
VkCommandBufferAllocateInfo allocInfo = {};
allocInfo.sType = VK_STRUCTURE_TYPE_COMMAND_BUFFER_ALLOCATE_INFO;
allocInfo.commandPool = commandPool;  // المستودع
allocInfo.level = VK_COMMAND_BUFFER_LEVEL_PRIMARY;  // مستوى أولي
allocInfo.commandBufferCount = MAX_FRAMES_IN_FLIGHT;  // عدد المخازن

// تخصيص المخازن
std::vector<VkCommandBuffer> commandBuffers(MAX_FRAMES_IN_FLIGHT);
VkResult result = vkAllocateCommandBuffers(device, &allocInfo, commandBuffers.data());

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل تخصيص مخازن الأوامر!");
}

// المخازن جاهزة للتسجيل
for (size_t i = 0; i < commandBuffers.size(); i++) {
    std::cout << "تم تخصيص مخزن الأوامر " << i << std::endl;
}

// تحرير مخزن أوامر واحد
vkFreeCommandBuffers(device, commandPool, 1, &commandBuffer);

// تحرير عدة مخازن
std::vector<VkCommandBuffer> buffersToFree = {cmd1, cmd2, cmd3};
vkFreeCommandBuffers(
    device,
    commandPool,
    static_cast<uint32_t>(buffersToFree.size()),
    buffersToFree.data()
);

// تعيين القيم NULL بعد التحرير
for (auto& buf : buffersToFree) {
    buf = VK_NULL_HANDLE;
}

// هيكل معلومات بداية التسجيل
VkCommandBufferBeginInfo beginInfo = {};
beginInfo.sType = VK_STRUCTURE_TYPE_COMMAND_BUFFER_BEGIN_INFO;

// تحديد كيفية استخدام المخزن
beginInfo.flags = VK_COMMAND_BUFFER_USAGE_ONE_TIME_SUBMIT_BIT;  // استخدام مرة واحدة
// الخيارات الأخرى:
// VK_COMMAND_BUFFER_USAGE_RENDER_PASS_CONTINUE_BIT  // استمرار Render Pass
// VK_COMMAND_BUFFER_USAGE_SIMULTANEOUS_USE_BIT  // استخدام متزامن

// للـ Secondary Command Buffer
// VkCommandBufferInheritanceInfo inheritanceInfo = {};
// beginInfo.pInheritanceInfo = &inheritanceInfo;

// بدء التسجيل
VkResult result = vkBeginCommandBuffer(commandBuffer, &beginInfo);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل بدء تسجيل مخزن الأوامر!");
}

// الآن يمكن تسجيل الأوامر...
// vkCmdBindPipeline(...)
// vkCmdDraw(...)
// ...

// إنهاء تسجيل مخزن الأوامر
VkResult result = vkEndCommandBuffer(commandBuffer);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنهاء تسجيل مخزن الأوامر!");
}

// المخزن جاهز للإرسال
std::cout << "مخزن الأوامر جاهز للتنفيذ" << std::endl;

// إعادة تعيين مخزن الأوامر
VkResult result = vkResetCommandBuffer(
    commandBuffer,
    VK_COMMAND_BUFFER_RESET_RELEASE_RESOURCES_BIT  // تحرير الموارد
);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إعادة تعيين مخزن الأوامر!");
}

// الآن يمكن إعادة التسجيل من البداية
vkBeginCommandBuffer(commandBuffer, &beginInfo);
// ...

// هيكل معلومات إنشاء الإشارة
VkSemaphoreCreateInfo semaphoreInfo = {};
semaphoreInfo.sType = VK_STRUCTURE_TYPE_SEMAPHORE_CREATE_INFO;
// لا توجد أعلام خاصة حالياً

// إنشاء إشارة انتظار الصورة
VkSemaphore imageAvailableSemaphore;
VkResult result = vkCreateSemaphore(
    device,
    &semaphoreInfo,
    nullptr,
    &imageAvailableSemaphore
);

// إنشاء إشارة انتهاء الرسم
VkSemaphore renderFinishedSemaphore;
result = vkCreateSemaphore(
    device,
    &semaphoreInfo,
    nullptr,
    &renderFinishedSemaphore
);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنشاء الإشارات!");
}

// تدمير الإشارات
vkDestroySemaphore(device, imageAvailableSemaphore, nullptr);
vkDestroySemaphore(device, renderFinishedSemaphore, nullptr);

imageAvailableSemaphore = VK_NULL_HANDLE;
renderFinishedSemaphore = VK_NULL_HANDLE;

// هيكل معلومات إنشاء السياج
VkFenceCreateInfo fenceInfo = {};
fenceInfo.sType = VK_STRUCTURE_TYPE_FENCE_CREATE_INFO;

// إنشاء السياج بحالة مُشارة (للسماح بالانتظار الأول)
fenceInfo.flags = VK_FENCE_CREATE_SIGNALED_BIT;

// إنشاء سياج لكل إطار
std::vector<VkFence> inFlightFences(MAX_FRAMES_IN_FLIGHT);

for (size_t i = 0; i < MAX_FRAMES_IN_FLIGHT; i++) {
    VkResult result = vkCreateFence(
        device,
        &fenceInfo,
        nullptr,
        &inFlightFences[i]
    );

    if (result != VK_SUCCESS) {
        throw std::runtime_error("فشل إنشاء السياج!");
    }
}

// تدمير جميع السياجات
for (size_t i = 0; i < inFlightFences.size(); i++) {
    vkDestroyFence(device, inFlightFences[i], nullptr);
    inFlightFences[i] = VK_NULL_HANDLE;
}

// انتظار السياج الحالي (للإطار الحالي)
VkResult result = vkWaitForFences(
    device,
    1,                              // عدد السياجات
    &inFlightFences[currentFrame],  // السياج
    VK_TRUE,                        // انتظار الكل
    UINT64_MAX                      // انتظار لانهائي
);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل انتظار السياج!");
}

// الآن الإطار السابق انتهى، يمكن إعادة استخدام الموارد

// إعادة تعيين السياج للاستخدام الجديد
VkResult result = vkResetFences(
    device,
    1,                              // عدد السياجات
    &inFlightFences[currentFrame]   // السياج
);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إعادة تعيين السياج!");
}

// الآن السياج جاهز للاستخدام مع vkQueueSubmit

// إعداد معلومات السطح
VkSurfaceFormatKHR surfaceFormat = chooseSwapSurfaceFormat(formats);
VkPresentModeKHR presentMode = chooseSwapPresentMode(presentModes);
VkExtent2D extent = chooseSwapExtent(capabilities);

// تحديد عدد الصور
uint32_t imageCount = capabilities.minImageCount + 1;
if (capabilities.maxImageCount > 0 && imageCount > capabilities.maxImageCount) {
    imageCount = capabilities.maxImageCount;
}

// هيكل معلومات إنشاء السلسلة
VkSwapchainCreateInfoKHR createInfo = {};
createInfo.sType = VK_STRUCTURE_TYPE_SWAPCHAIN_CREATE_INFO_KHR;
createInfo.surface = surface;  // السطح

createInfo.minImageCount = imageCount;  // عدد الصور
createInfo.imageFormat = surfaceFormat.format;  // تنسيق الصور
createInfo.imageColorSpace = surfaceFormat.colorSpace;  // فضاء الألوان
createInfo.imageExtent = extent;  // أبعاد الصور
createInfo.imageArrayLayers = 1;  // عدد الطبقات
createInfo.imageUsage = VK_IMAGE_USAGE_COLOR_ATTACHMENT_BIT;  // استخدام الرسم

// إعداد الطوابير
uint32_t queueFamilyIndices[] = {
    graphicsQueueFamilyIndex,
    presentQueueFamilyIndex
};

if (graphicsQueueFamilyIndex != presentQueueFamilyIndex) {
    createInfo.imageSharingMode = VK_SHARING_MODE_CONCURRENT;
    createInfo.queueFamilyIndexCount = 2;
    createInfo.pQueueFamilyIndices = queueFamilyIndices;
} else {
    createInfo.imageSharingMode = VK_SHARING_MODE_EXCLUSIVE;
    createInfo.queueFamilyIndexCount = 0;
    createInfo.pQueueFamilyIndices = nullptr;
}

createInfo.preTransform = capabilities.currentTransform;  // التحويل
createInfo.compositeAlpha = VK_COMPOSITE_ALPHA_OPAQUE_BIT_KHR;  // الشفافية
createInfo.presentMode = presentMode;  // وضع العرض
createInfo.clipped = VK_TRUE;  // قص البيكسلات المخفية
createInfo.oldSwapchain = VK_NULL_HANDLE;  // السلسلة القديمة

// إنشاء السلسلة
VkSwapchainKHR swapchain;
VkResult result = vkCreateSwapchainKHR(device, &createInfo, nullptr, &swapchain);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنشاء سلسلة التبديل!");
}

// تدمير سلسلة التبديل
vkDestroySwapchainKHR(device, swapchain, nullptr);
swapchain = VK_NULL_HANDLE;

// الخطوة 1: الحصول على عدد الصور
uint32_t imageCount;
vkGetSwapchainImagesKHR(device, swapchain, &imageCount, nullptr);

// الخطوة 2: الحصول على الصور
std::vector<VkImage> swapchainImages(imageCount);
vkGetSwapchainImagesKHR(device, swapchain, &imageCount, swapchainImages.data());

// الخطوة 3: إنشاء Image Views لكل صورة
std::vector<VkImageView> swapchainImageViews(imageCount);

for (size_t i = 0; i < imageCount; i++) {
    VkImageViewCreateInfo createInfo = {};
    createInfo.sType = VK_STRUCTURE_TYPE_IMAGE_VIEW_CREATE_INFO;
    createInfo.image = swapchainImages[i];
    createInfo.viewType = VK_IMAGE_VIEW_TYPE_2D;
    createInfo.format = swapchainImageFormat;
    createInfo.components.r = VK_COMPONENT_SWIZZLE_IDENTITY;
    createInfo.components.g = VK_COMPONENT_SWIZZLE_IDENTITY;
    createInfo.components.b = VK_COMPONENT_SWIZZLE_IDENTITY;
    createInfo.components.a = VK_COMPONENT_SWIZZLE_IDENTITY;
    createInfo.subresourceRange.aspectMask = VK_IMAGE_ASPECT_COLOR_BIT;
    createInfo.subresourceRange.baseMipLevel = 0;
    createInfo.subresourceRange.levelCount = 1;
    createInfo.subresourceRange.baseArrayLayer = 0;
    createInfo.subresourceRange.layerCount = 1;

    vkCreateImageView(device, &createInfo, nullptr, &swapchainImageViews[i]);
}

// الحصول على الصورة التالية
uint32_t imageIndex;
VkResult result = vkAcquireNextImageKHR(
    device,
    swapchain,
    UINT64_MAX,              // انتظار لانهائي
    imageAvailableSemaphore, // إشارة عند توفر الصورة
    VK_NULL_HANDLE,          // لا سياج
    &imageIndex              // فهرس الصورة
);

// معالجة حالات إعادة إنشاء السلسلة
if (result == VK_ERROR_OUT_OF_DATE_KHR) {
    // تغيير حجم النافذة - يجب إعادة إنشاء السلسلة
    recreateSwapChain();
    return;
} else if (result == VK_SUBOPTIMAL_KHR) {
    // السلسلة تعمل لكن ليست مثالية
    // يمكن المتابعة أو إعادة الإنشاء
} else if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل الحصول على صورة السلسلة!");
}

// imageIndex الآن يحتوي على فهرس الصورة للرسم
// يمكن استخدامه مع commandBuffers[imageIndex]

// إعداد هيكل العرض
VkPresentInfoKHR presentInfo = {};
presentInfo.sType = VK_STRUCTURE_TYPE_PRESENT_INFO_KHR;

// تحديد إشارات الانتظار
