VkDescriptorPoolCreateInfo poolInfo = {};
poolInfo.sType = VK_STRUCTURE_TYPE_DESCRIPTOR_POOL_CREATE_INFO;
poolInfo.poolSizeCount = static_cast<uint32_t>(poolSizes.size());
poolInfo.pPoolSizes = poolSizes.data();
poolInfo.maxSets = static_cast<uint32_t>(MAX_FRAMES_IN_FLIGHT);  // أقصى عدد Sets
poolInfo.flags = 0;  // بدون أعلام خاصة

VkDescriptorPool descriptorPool;
VkResult result = vkCreateDescriptorPool(
    device, &poolInfo, nullptr, &descriptorPool
);

if (result != VK_SUCCESS) {
    throw std::runtime_error("فشل إنشاء Descriptor Pool!");
}

// تدمير Descriptor Pool
vkDestroyDescriptorPool(device, descriptorPool, nullptr);
descriptorPool = VK_NULL_HANDLE;

// تخصيص Descriptor Set لكل إطار
std::vector<VkDescriptorSet> descriptorSets(MAX_FRAMES_IN_FLIGHT);

for (size_t i = 0; i < MAX_FRAMES_IN_FLIGHT; i++) {
    VkDescriptorSetAllocateInfo allocInfo = {};
    allocInfo.sType = VK_STRUCTURE_TYPE_DESCRIPTOR_SET_ALLOCATE_INFO;
    allocInfo.descriptorPool = descriptorPool;
    allocInfo.descriptorSetCount = 1;
    allocInfo.pSetLayouts = &descriptorSetLayout;

    VkResult result = vkAllocateDescriptorSets(
        device, &allocInfo, &descriptorSets[i]
    );

    if (result != VK_SUCCESS) {
        throw std::runtime_error("فشل تخصيص Descriptor Set!");
    }
}

// معلومات الـ Uniform Buffer
VkDescriptorBufferInfo bufferInfo = {};
bufferInfo.buffer = uniformBuffers[i];
bufferInfo.offset = 0;
bufferInfo.range = sizeof(UniformBufferObject);

// معلومات الـ Image
VkDescriptorImageInfo imageInfo = {};
imageInfo.imageLayout = VK_IMAGE_LAYOUT_SHADER_READ_ONLY_OPTIMAL;
imageInfo.imageView = textureImageView;
imageInfo.sampler = textureSampler;

// كتابة الـ Uniform Buffer
VkWriteDescriptorSet descriptorWrite = {};
descriptorWrite.sType = VK_STRUCTURE_TYPE_WRITE_DESCRIPTOR_SET;
descriptorWrite.dstSet = descriptorSets[i];  // المجموعة
descriptorWrite.dstBinding = 0;  // رقم الربط
descriptorWrite.dstArrayElement = 0;  // فهرس المصفوفة
descriptorWrite.descriptorType = VK_DESCRIPTOR_TYPE_UNIFORM_BUFFER;
descriptorWrite.descriptorCount = 1;
descriptorWrite.pBufferInfo = &bufferInfo;

// كتابة الـ Sampler
VkWriteDescriptorSet samplerWrite = {};
samplerWrite.sType = VK_STRUCTURE_TYPE_WRITE_DESCRIPTOR_SET;
samplerWrite.dstSet = descriptorSets[i];
samplerWrite.dstBinding = 1;
samplerWrite.dstArrayElement = 0;
samplerWrite.descriptorType = VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER;
samplerWrite.descriptorCount = 1;
samplerWrite.pImageInfo = &imageInfo;

// تحديث الواصفات
std::array<VkWriteDescriptorSet, 2> writes = { descriptorWrite, samplerWrite };
vkUpdateDescriptorSets(
    device,
    static_cast<uint32_t>(writes.size()),
    writes.data(),
    0,       // بدون نسخ
    nullptr
);

// ربط Descriptor Set
vkCmdBindDescriptorSets(
    commandBuffer,
    VK_PIPELINE_BIND_POINT_GRAPHICS,  // للرسوميات
    pipelineLayout,                    // التخطيط
    0,                                 // المجموعة الأولى
    1,                                 // عدد المجموعات
    &descriptorSets[currentFrame],     // المجموعة
    0,                                 // بدون إزاحات ديناميكية
    nullptr
);

